mapper.update:
UPDATE reservation
SET content = #{content},
    status  = #{status}
WHERE id = #{id}

mapper.select:
SELECT id, admin_id, reservation_at, content, status, created_at, updated_at
FROM reservation
WHERE id = #{id}

SELECT id, admin_id, reservation_at, content, status, created_at, updated_at
FROM reservation
WHERE admin_id = #{adminId}
  AND DATE(reservation_at) BETWEEN #{startDate} AND #{endDate}
ORDER BY reservation_at
